package com.chaobo.scm.supplier.domain.quality;public enum QualityIssueStatus{OPEN(1,"待处理"),RECTIFYING(2,"整改中"),PENDING_VERIFICATION(3,"待审核"),CLOSED(4,"已关闭"),OVERDUE(5,"已逾期");private final int code;private final String label;QualityIssueStatus(int code,String label){this.code=code;this.label=label;}public int code(){return code;}public String label(){return label;}public static QualityIssueStatus fromCode(int code){for(var v:values())if(v.code==code)return v;throw new IllegalArgumentException("未知质量问题状态");}}
